function solve(prices, strategy, k) {
    const n = prices.length;
    let original_profit = 0;
    for (let i = 0; i < n; i++) {
        original_profit += strategy[i] * prices[i];
    }

    const prefix_price = new Array(n + 1).fill(0);
    const prefix_strat_price = new Array(n + 1).fill(0);

    for (let i = 0; i < n; i++) {
        prefix_price[i + 1] = prefix_price[i] + prices[i];
        prefix_strat_price[i + 1] = prefix_strat_price[i] + strategy[i] * prices[i];
    }

    const m = k / 2;
    let max_change = 0;

    for (let i = 0; i <= n - k; i++) {
        const end_second_half = i + k;
        const start_second_half = i + m;
        const sum_second_half = prefix_price[end_second_half] - prefix_price[start_second_half];
        const sum_original = prefix_strat_price[i + k] - prefix_strat_price[i];
        const change = sum_second_half - sum_original;
        if (change > max_change) {
            max_change = change;
        }
    }

    return original_profit + Math.max(0, max_change);
}

